import React, {useEffect, useState} from 'react';
import {useNavigate} from 'react-router-dom';
import {useMemberWallet} from "../../../hooks/useMemberWallet";
import {setComma, wonAndPercentFormat} from "../../../utils/format";
import {getRefundFeeInfo, refundPrepaidBalance} from "../../../api/transaction/refundApi";
import {RefundInfoType} from "../../../types/transaction/refund.info.type";
import {alertAfterFunction, defaultAlert, defaultConfirm} from "../../../utils/alert";
import {AccountInfo} from "../../../components/bank/AccountInfo";
import {Loading} from "../../../components/common/Loading";
import {BalanceArea} from "../../../components/bank/BalanceArea";


const RefundPage = () => {
    const navigate = useNavigate();
    const {memberWalletInfo, loading: walletLoading, error, refetch} = useMemberWallet();
    const [loading, setLoading] = useState(true);
    const [refundInfo, setRefundInfo] = useState<RefundInfoType>();


    useEffect(() => {
        getMemberRefundInfo();
    }, []);



    const getMemberRefundInfo = async () => {
        try {
            setLoading(true);
            const response = await getRefundFeeInfo();
            if (response.data?.code == "00") {
                setRefundInfo(response.data.data);
            }
        } catch (err) {
            console.error('Failed to fetch getMemberWalletBalance:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleRefund = () => {
        defaultConfirm("총 " + setComma(Number(refundInfo?.refundAmount)) + "원 환불 신청 하시겠습니까?", "신청", "취소",
            (isConfirmed) => {
                if (isConfirmed) {
                    refund();
                } else {
                    return;
                }
            }
        );
    }

    const refund = async () => {
        try {
            const response = await refundPrepaidBalance();
            if (response.data?.code === "00") {
                alertAfterFunction("잔액환불 신청이 완료되었습니다.", () => navigate('/wallet/refund-list'));
            }
        } catch (e) {
            defaultAlert("잔액 환불 신청에 실패했습니다.");
            return;
        }
    }

    if (!refundInfo) {
        return (
            <Loading loading={loading} onClose={() => setLoading(false)}/>
        );
    }



    return (
        <div>
            {refundInfo.refundAmount > 0 && (
                <div className="bottom-btn">
                    <button type="button" className="btn confirm" onClick={handleRefund}>
                        잔액환불 신청하기
                    </button>
                </div>
            )}

            <main className="container type_gray">
                <section className="bg-white">
                    <div className="inner-box">
                        <BalanceArea
                            className={"main-wallet wallet"}
                            title={"보유 잔액"}
                            balance={Number(refundInfo.prepaidBalance || 0)}
                            expectedBalance={0}
                            expectedBalanceShow={false}
                        />
                    </div>
                </section>

                <section className="bg-white">
                    <div className="inner-box">
                        <div className="form-item">
                            <label className="input-tit big">환불정보</label>
                            <div className="info-row">
                                <span className="label">환불가능금액</span>
                                <span className="cont">{setComma(Number(refundInfo.refundableAmount || 0))}원</span>
                            </div>
                            <div className="info-row">
                                <span className="label">환불 수수료</span>
                                <span className="cont">{setComma(Number(refundInfo.refundFee || 0))}원</span>
                            </div>
                            <div className="info-row top-line">
                <span className="label">
                  <strong>실 환불금액</strong>
                </span>
                                <span className="cont">
                  <strong>{setComma(Number(refundInfo.refundAmount || 0))}원</strong>
                </span>
                            </div>
                        </div>
                        <div className="guide-box mt20">
                            <h3 className="point-tit">환불 수수료 안내</h3>
                            <ul className="guidF-list">
                                <li>환불 금액 10,000원 이하 : {setComma(Number(refundInfo.refundFeeUnderValue || 0))}{wonAndPercentFormat(refundInfo.refundFeeUnderUnit)}</li>
                                <li>환불 금액 10,000원 초과 : {setComma(Number(refundInfo.refundFeeOverValue || 0))}{wonAndPercentFormat(refundInfo.refundFeeOverUnit)}</li>
                            </ul>
                        </div>
                    </div>
                </section>
                <AccountInfo
                    title={"환불계좌"}
                    depositor={memberWalletInfo?.memberName}
                    accountNo={memberWalletInfo?.accountNo}
                    bankName={memberWalletInfo?.bankName}
                />

                <section className="no-gap">
                    <div className="inner-box">
                        <ul className="guidF-list">
                            <li>잔액환불 신청 후 3영업일 내 환불계좌로 지급됩니다.</li>
                            <li>
                                최근 7일 내 충전 후 미사용한 충전금액은 잔액환불 대상이 아닙니다.
                                (내 지갑 &gt; 충전의 충전 상세내역에서 충전취소 하실 수 있습니다.)
                            </li>
                        </ul>
                    </div>
                </section>
            </main>
        </div>
    );
};

export default RefundPage;
